from django.http import HttpResponse


def demo_shell():
    return HttpResponse("""<!doctype html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>AgentLand</title><style>body{margin:0;background:#edf4e9;color:#17212b;font-family:ui-monospace,Consolas,monospace}main{max-width:900px;margin:auto;padding:36px 20px}h1{margin:0}.tag{background:#17212b;color:#fff;padding:6px 9px;font-size:12px}.grid{display:grid;grid-template-columns:1fr 1fr;gap:16px;margin-top:22px}.box{background:#fff;border:3px solid #17212b;padding:16px;box-shadow:5px 5px #b6c5bd}input,select,button{font:inherit;padding:9px;border:2px solid #17212b}input,select{width:100%;box-sizing:border-box;margin:8px 0}button{background:#d9e8f5;cursor:pointer;margin:5px 5px 5px 0}.session{border-top:1px solid #ccd6c8;padding:12px 0;font-size:13px}.note{font-size:12px;color:#53616a}.error{color:#9b2424}@media(max-width:650px){.grid{grid-template-columns:1fr}}</style></head><body><main><span class="tag">AGENTLAND LIVE DEMO</span><h1>Execution evidence, made explorable.</h1><p>Create a bounded session, choose a transparent runner, and open the city without constructing URLs.</p><div class="grid"><section class="box"><h2>Create session</h2><label>Mission<input id="mission" value="Repair whiteboard room isolation"></label><label>Runner<select id="runner"><option value="deterministic">Deterministic Demo</option><option value="codex">Codex — unavailable in current environment</option></select></label><p class="note" id="mode-note">Demonstration runner used to validate the AgentLand evidence pipeline.</p><button id="create">Create Session</button><button id="showcase">Run Evidence Demo</button><button id="reset">Reset broken baseline</button><p id="message" class="note"></p></section><section class="box"><h2>Existing sessions</h2><div id="sessions">Loading…</div></section></div></main><script>const q=s=>document.querySelector(s),message=q('#message');function say(t,err=false){message.textContent=t;message.className=err?'error':'note'}q('#runner').onchange=()=>q('#mode-note').textContent=q('#runner').value==='codex'?'Codex is requested with least privilege; this Windows environment may deny process launch before execution.':'Demonstration runner used to validate the AgentLand evidence pipeline.';async function load(){const r=await fetch('/agentland/sessions/'),data=await r.json(),box=q('#sessions');box.replaceChildren();if(!data.sessions.length){box.textContent='No sessions yet.';return}data.sessions.forEach(s=>{const row=document.createElement('div');row.className='session';const title=document.createElement('div');title.textContent=s.mission+' · '+s.status+' · '+s.current_sequence+' events';const city=document.createElement('a');city.href='/agentland/sessions/'+s.id+'/city/';city.textContent='Open City';city.style.marginRight='10px';const start=document.createElement('button');start.textContent='Start Builder';start.onclick=()=>startRun(s.id,q('#runner').value);row.append(title,city,start);box.appendChild(row)})}async function create(){const r=await fetch('/agentland/sessions/',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({mission:q('#mission').value})}),data=await r.json();if(!r.ok){say(data.error,true);return}location.href='/agentland/sessions/'+data.id+'/city/'}async function startRun(id,runner){say('Dispatching '+runner+' runner…');const r=await fetch('/agentland/sessions/'+id+'/dispatch-builder/',{method:'POST',headers:{'Content-Type':'application/json','Idempotency-Key':crypto.randomUUID()},body:JSON.stringify({runner_identity:runner})}),data=await r.json();if(!r.ok){say(data.error,true);return}location.href='/agentland/sessions/'+id+'/city/'}q('#create').onclick=create;q('#reset').onclick=async()=>{const r=await fetch('/agentland/reset-baseline/',{method:'POST'});say(r.ok?'Broken baseline restored.':(await r.json()).error,!r.ok)};q('#showcase').onclick=async()=>{await fetch('/agentland/reset-baseline/',{method:'POST'});const r=await fetch('/agentland/sessions/',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({mission:q('#mission').value})}),s=await r.json();if(!r.ok){say(s.error,true);return}location.href='/agentland/sessions/'+s.id+'/city/?autostart=deterministic'};load();</script></body></html>""")
